SELECT COUNT(DISTINCT lea_id) AS total_districts
FROM local_agencies
WHERE lea_type = 'district';

SELECT lea_type, COUNT(*) AS agency_count
FROM local_agencies
GROUP BY lea_type;

SELECT COUNT(charter_id) AS active_charter_schools_count
FROM charter_schools
WHERE charter_status = 'active';

SELECT lea_type, COUNT(*) AS agency_count
FROM local_agencies
GROUP BY lea_type;

SELECT lea_name, accreditation_status
FROM local_agencies
ORDER BY accreditation_status DESC;
